    std::string Trim(const std::string& value)
    {
        size_t first = 0;
        while (first < value.size() && std::isspace(static_cast<unsigned char>(value[first])))
        {
            ++first;
        }

        size_t last = value.size();
        while (last > first && std::isspace(static_cast<unsigned char>(value[last - 1])))
        {
            --last;
        }

        return value.substr(first, last - first);
    }

    std::string RemoveUtf8Bom(const std::string& value)
    {
        if (value.size() >= 3 &&
            static_cast<unsigned char>(value[0]) == 0xEF &&
            static_cast<unsigned char>(value[1]) == 0xBB &&
            static_cast<unsigned char>(value[2]) == 0xBF)
        {
            return value.substr(3);
        }
        return value;
    }

    bool ContainsText(const std::vector<std::string>& values, const std::string& text)
    {
        for (const std::string& value : values)
        {
            if (value == text)
            {
                return true;
            }
        }
        return false;
    }

    void AddUniqueText(std::vector<std::string>& values, const std::string& text)
    {
        if (!text.empty() && !ContainsText(values, text))
        {
            values.push_back(text);
        }
    }

    std::vector<std::string> LoadMaterialConfig()
    {
        std::ifstream file(MaterialConfigFilePath(), std::ios::binary);
        if (!file)
        {
            return DefaultMaterials();
        }

        std::vector<std::string> materials;
        bool inMaterials = false;
        bool firstLine = true;
        std::string line;
        while (std::getline(file, line))
        {
            if (firstLine)
            {
                line = RemoveUtf8Bom(line);
                firstLine = false;
            }

            const std::string value = Trim(line);
            if (value.empty() || value[0] == '#' || value[0] == ';')
            {
                continue;
            }

            if (value.front() == '[' && value.back() == ']')
            {
                inMaterials = Trim(value.substr(1, value.size() - 2)) == "材料";
                continue;
            }

            if (inMaterials)
            {
                AddUniqueText(materials, value);
            }
        }

        return materials.empty() ? DefaultMaterials() : materials;
    }

    std::vector<NXOpen::NXString> ToNxStrings(const std::vector<std::string>& values)
    {
        std::vector<NXOpen::NXString> result;
        result.reserve(values.size());
        for (const std::string& value : values)
        {
            result.push_back(NXOpen::NXString(value, NXOpen::NXString::UTF8));
        }
        return result;
    }

    std::string Utf8Text(const NXOpen::NXString& value)
    {
        const char* text = value.GetUTF8Text();
        return text == NULL ? std::string() : std::string(text);
    }

    void SetStringBlockValue(NXOpen::BlockStyler::StringBlock* block, const NXOpen::NXString& value)
    {
        if (block == NULL)
        {
            return;
        }

        block->SetValue(value);
    }

    void ApplyMaterialItems(NXOpen::BlockStyler::StringBlock* block, const std::vector<std::string>& materials)
    {
        if (block == NULL)
        {
            throw std::runtime_error("未找到材料控件。");
        }
        if (materials.empty())
        {
            throw std::runtime_error("材料配置不能为空。");
        }

        const std::string previousValue = Utf8Text(block->Value());
        std::vector<NXOpen::NXString> items = ToNxStrings(materials);
        block->SetListItems(items);
        block->SetPresentationStyleAsString("Combo");
        block->SetReadOnlyString(true);

        if (ContainsText(materials, previousValue))
        {
            block->SetValue(NXOpen::NXString(previousValue, NXOpen::NXString::UTF8));
        }
        else
        {
            block->SetValue(items.front());
        }
    }

    void SetMaterialValueIfPresent(NXOpen::BlockStyler::StringBlock* block, const NXOpen::NXString& value)
    {
        const std::vector<std::string> materials = LoadMaterialConfig();
        ApplyMaterialItems(block, materials);

        const std::string text = Utf8Text(value);
        if (ContainsText(materials, text))
        {
            SetStringBlockValue(block, NXOpen::NXString(text, NXOpen::NXString::UTF8));
        }
    }

