    void RefreshAllDrawingSheetViews(NXOpen::Part* workPart)
    {
        if (workPart == NULL)
        {
            return;
        }

        NXOpen::Drawings::DrawingSheetCollection* drawingSheets = workPart->DrawingSheets();
        NXOpen::Drawings::DrawingSheet* currentSheet = drawingSheets->CurrentDrawingSheet();

        for (NXOpen::Drawings::DrawingSheetCollection::iterator it = drawingSheets->begin(); it != drawingSheets->end(); ++it)
        {
            NXOpen::Drawings::DrawingSheet* sheet = *it;
            if (sheet == NULL)
            {
                continue;
            }

            sheet->Open();
            workPart->DraftingViews()->UpdateViews(NXOpen::Drawings::DraftingViewCollection::ViewUpdateOptionAll, sheet);
        }

        if (currentSheet != NULL)
        {
            currentSheet->Open();
        }
    }

    NXOpen::Expression* FindExpression(NXOpen::Part* workPart, const char* name)
    {
        try
        {
            return dynamic_cast<NXOpen::Expression*>(workPart->Expressions()->FindObject(name));
        }
        catch (exception&)
        {
            return NULL;
        }
    }

    NXOpen::Expression* CreateOrUpdateExpression(NXOpen::Part* workPart, const char* type, const char* name, const char* formula, NXOpen::Unit* unit)
    {
        NXOpen::Expression* expression = FindExpression(workPart, name);
        if (expression != NULL)
        {
            expression->SetFormula(formula);
            return expression;
        }

        char equation[256];
        sprintf(equation, "%s=%s", name, formula);
        return workPart->Expressions()->CreateExpressionWithUnit(type, equation, unit);
    }

    void NameExpressionIfAvailable(NXOpen::Part* workPart, NXOpen::Expression* expression, const char* name)
    {
        if (expression == NULL || FindExpression(workPart, name) != NULL)
        {
            return;
        }

        expression->SetName(name);
    }

